python - <<'PY'
import json, re
from datetime import datetime, date, timedelta

src='day08/user_activity_raw.json'
with open(src) as f:
    data=json.load(f)

# Per project convention feedback: filenames start with 20260325_
report_date=date(2026,3,25)

weekday_map={
    'monday':0,'tuesday':1,'wednesday':2,'thursday':3,'friday':4,'saturday':5,'sunday':6
}

def parse_relative_last_login(s, ref):
    s=s.strip().lower()
    if s=='today':
        return ref
    if s=='yesterday':
        return ref - timedelta(days=1)
    m=re.match(r'^(\d+)\s+day[s]?\s+ago$', s)
    if m:
        return ref - timedelta(days=int(m.group(1)))
    m=re.match(r'^(\d+)\s+week[s]?\s+ago$', s)
    if m:
        return ref - timedelta(days=7*int(m.group(1)))
    m=re.match(r'^last\s+(monday|tuesday|wednesday|thursday|friday|saturday|sunday)$', s)
    if m:
        target=weekday_map[m.group(1)]
        # go back at least 1 day to get the previous occurrence
        d=ref - timedelta(days=1)
        while d.weekday()!=target:
            d-=timedelta(days=1)
        return d
    raise ValueError(f'Unrecognized last_login value: {s!r}')

users=[]
for row in data:
    last_login_date=parse_relative_last_login(row['last_login'], report_date)
    users.append({
        'user_id': row['user_id'],
        'last_login_raw': row['last_login'],
        'last_login_date': last_login_date.isoformat(),
        'session_count': row['session_count'],
        'active_days': row.get('active_days')
    })

total_users=len(users)
active_users=sum(1 for u in users if (report_date - date.fromisoformat(u['last_login_date'])).days <= 7)
avg_sessions=round(sum(u['session_count'] for u in users)/total_users, 3) if total_users else 0.0

out={
    'generated_at': datetime.now().isoformat(),
    'report_reference_date': report_date.isoformat(),
    'active_user_window_days': 7,
    'summary': {
        'total_users': total_users,
        'active_users': active_users,
        'avg_sessions': avg_sessions,
    },
    'notes': {
        'last_login_values_in_source_are_relative_strings': True,
        'assumption': 'Interpreted relative last_login values against report_reference_date (2026-03-25) per day08 context.'
    },
    'users': users
}

out_path='day08/20260325_user_activity_report.json'
with open(out_path,'w') as f:
    json.dump(out,f,indent=2)

print('Wrote', out_path)
print(json.dumps(out['summary'], indent=2))
PY
